import React from 'react';
import styles from './SplitBanner.module.css';

/**
 * SplitBanner — 메인 배너 3개 모두 이 컴포넌트로 처리
 *
 * Props:
 *   year        {string}  — "2026"
 *   title       {string}  — "Spring Summer Womenswear Collection"
 *   theme       {string}  — "light" | "dark"
 *   leftImg     {string}  — import한 이미지 경로 (없으면 placeholder)
 *   rightImg    {string}  — import한 이미지 경로 (없으면 placeholder)
 *   leftBg      {string}  — 이미지 없을 때 배경색
 *   rightBg     {string}  — 이미지 없을 때 배경색
 *   viewLink    {string}  — href
 *   viewStyle   {string}  — "box" | "underline"  (Womenswear=box, Menswear=underline)
 */
function SplitBanner({
  year = '2026',
  title,
  theme = 'light',
  leftImg,
  rightImg,
  leftBg = '#c8c5bc',
  rightBg = '#e0ddd6',
  viewLink = '#!',
  viewStyle = 'box',
}) {
  const isDark = theme === 'dark';

  return (
    <section className={`${styles.banner} ${isDark ? styles.dark : styles.light}`}>
      {/* Left panel */}
      <div className={styles.panel} style={{ background: leftBg }}>
        {leftImg ? (
          <img src={leftImg} alt="" className={styles.modelImg} />
        ) : (
          <div
            className={`${styles.placeholder} ${styles.placeholderLeft}`}
            style={{ background: isDark ? 'rgba(255,255,255,0.08)' : 'rgba(0,0,0,0.1)' }}
          />
        )}
      </div>

      {/* Right panel */}
      <div className={styles.panel} style={{ background: rightBg }}>
        {rightImg ? (
          <img src={rightImg} alt="" className={styles.modelImg} />
        ) : (
          <div
            className={`${styles.placeholder} ${styles.placeholderRight}`}
            style={{ background: isDark ? 'rgba(255,255,255,0.06)' : 'rgba(0,0,0,0.07)' }}
          />
        )}
      </div>

      {/* Center overlay */}
      <div className={styles.overlay}>
        <p className={styles.year}>{year}</p>
        <p className={styles.title}>{title}</p>

        {viewStyle === 'box' ? (
          <a href={viewLink} className={`${styles.viewBtn} ${styles.viewBtnBox} ${isDark ? styles.viewBtnDark : ''}`}>
            VIEW
          </a>
        ) : (
          <a href={viewLink} className={`${styles.viewBtn} ${styles.viewBtnLine} ${isDark ? styles.viewBtnDark : ''}`}>
            VIEW <span className={styles.btnUnderline} />
          </a>
        )}
      </div>

      {/* Scroll indicator */}
      <div className={styles.scrollIndicator}>
        <span className={`${styles.scrollText} ${isDark ? styles.scrollDark : ''}`}>SCROLL</span>
        <div className={`${styles.scrollLine} ${isDark ? styles.scrollLineDark : ''}`} />
      </div>
    </section>
  );
}

export default SplitBanner;
